import React, { useEffect, useRef, useState } from "react";
import { createBooking, getMyBookings } from "../api";

function FuelBookingPage({ token }) {
  const [fuelType, setFuelType] = useState("Petrol");
  const [quantity, setQuantity] = useState(1);
  const [latitude, setLatitude] = useState(null);
  const [longitude, setLongitude] = useState(null);
  const [address, setAddress] = useState("");
  const [locationStatus, setLocationStatus] = useState("");

  const [imageData, setImageData] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [bookings, setBookings] = useState([]);

  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);

  const loadBookings = async () => {
    try {
      const data = await getMyBookings(token);
      setBookings(data.bookings || []);
    } catch (err) {
      setError(err.message);
    }
  };

  useEffect(() => {
    console.log("[FuelBookingPage] Component mounted. Requesting geolocation...");
    loadBookings();

    if (!navigator.geolocation) {
      console.log("[FuelBookingPage] Geolocation API not supported.");
      setLocationStatus("Geolocation is not supported by this browser.");
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const lat = position.coords.latitude;
        const lng = position.coords.longitude;
        const coordsText = `Lat: ${lat.toFixed(6)}, Lng: ${lng.toFixed(6)}`;

        console.log("[FuelBookingPage] Geolocation success:", { lat, lng });

        setLatitude(lat);
        setLongitude(lng);
        setAddress(coordsText); // Keep backend payload compatible (address is required)
        setLocationStatus("Location captured successfully.");
      },
      (geoError) => {
        console.log("[FuelBookingPage] Geolocation error:", geoError);

        if (geoError.code === 1) {
          setLocationStatus("Permission denied. Please allow location access.");
          alert("Location permission denied. Please allow location access and reload the page.");
        } else if (geoError.code === 2) {
          setLocationStatus("Location unavailable. Please enable GPS/location services.");
        } else if (geoError.code === 3) {
          setLocationStatus("Location request timed out. Please reload and try again.");
        } else {
          setLocationStatus("Unable to fetch location.");
        }
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0,
      }
    );

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach((track) => track.stop());
      }
    };
  }, []);

  const startCamera = async () => {
    setError("");
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("Unable to access camera. Please allow camera permissions.");
    }
  };

  const captureImage = () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;

    const context = canvas.getContext("2d");
    canvas.width = video.videoWidth || 320;
    canvas.height = video.videoHeight || 240;
    context.drawImage(video, 0, 0, canvas.width, canvas.height);
    setImageData(canvas.toDataURL("image/png"));
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
  };

  const submit = async (event) => {
    event.preventDefault();
    setMessage("");
    setError("");

    if (latitude === null || longitude === null) {
      setError("Location is required. Please allow location permission and reload.");
      return;
    }

    try {
      await createBooking(
        {
          fuelType,
          quantity: Number(quantity),
          address,
          imageData,
        },
        token
      );
      setMessage("Fuel booking submitted successfully.");
      setQuantity(1);
      setImageData("");
      await loadBookings();
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div>
      <h3>Fuel Booking</h3>

      <p>
        <strong>Latitude:</strong> {latitude !== null ? latitude : "Not available"}
      </p>
      <p>
        <strong>Longitude:</strong> {longitude !== null ? longitude : "Not available"}
      </p>
      {locationStatus && <p>{locationStatus}</p>}

      <form onSubmit={submit} className="stack">
        <label>Fuel Type</label>
        <select value={fuelType} onChange={(e) => setFuelType(e.target.value)}>
          <option>Petrol</option>
          <option>Diesel</option>
          <option>CNG</option>
          <option>EV Charge</option>
        </select>

        <label>Quantity (Liters / Units)</label>
        <input
          type="number"
          min="1"
          step="0.5"
          value={quantity}
          onChange={(e) => setQuantity(e.target.value)}
          required
        />

        <label>Detected Delivery Location</label>
        <textarea
          value={address}
          readOnly
          placeholder="Detecting your location..."
          required
        />

        <div className="camera-row">
          <button type="button" onClick={startCamera}>
            Start Camera
          </button>
          <button type="button" onClick={captureImage}>
            Capture Image
          </button>
          <button type="button" className="secondary" onClick={stopCamera}>
            Stop Camera
          </button>
        </div>

        <video ref={videoRef} autoPlay playsInline className="preview" />
        <canvas ref={canvasRef} className="hidden" />
        {imageData && <img src={imageData} alt="Captured" className="preview" />}

        <button type="submit">Book Fuel</button>
      </form>

      {message && <p className="success">{message}</p>}
      {error && <p className="error">{error}</p>}

      <h4>Your Bookings</h4>
      <ul className="list">
        {bookings.map((item) => (
          <li key={item.id}>
            {item.fuelType} | {item.quantity} | {item.status} |{" "}
            {new Date(item.createdAt).toLocaleString()}
          </li>
        ))}
        {bookings.length === 0 && <li>No bookings yet.</li>}
      </ul>
    </div>
  );
}

export default FuelBookingPage;
